fn strategyFromLabel(label: []const u8) ?ts_resolver.Strategy {
    if (std.ascii.eqlIgnoreCase(label, "classic")) return .classic;
    if (std.ascii.eqlIgnoreCase(label, "node") or
        std.ascii.eqlIgnoreCase(label, "node10")) return .node10;
    if (std.ascii.eqlIgnoreCase(label, "node16")) return .node16;
    if (std.ascii.eqlIgnoreCase(label, "nodenext")) return .nodenext;
    if (std.ascii.eqlIgnoreCase(label, "bundler")) return .bundler;
    return null;
}

/// Routed compile path. Returns `null` to fall back to the legacy
/// path when something prevents the program-graph route (no virtual
/// files extracted, etc.).
/// Scan node_modules `package.json` virtual files for a `types` /
/// `typings` field that names an ABSOLUTE path (e.g.
/// `"/.ts/typescript.d.ts"`). When the named declaration file isn't
/// already a virtual file, synthesize an empty `.d.ts` stub at that
/// path so the resolver resolves the package to a typed (`any`-shaped)
/// module instead of failing with TS2307 — matching the upstream test
/// harness, which mounts the real declaration files at `/.ts/...`.
fn synthesizeAbsoluteTypesStubs(
    gpa: std.mem.Allocator,
    files: []const VirtualFile,
    vfs: *ts_resolver.VirtualFs,
) !void {
    for (files) |f| {
        if (!std.mem.endsWith(u8, f.path, "package.json")) continue;
        if (!isNodeModulesVirtualPath(f.path)) continue;
        var parsed = std.json.parseFromSlice(std.json.Value, gpa, f.source, .{}) catch continue;
        defer parsed.deinit();
        if (parsed.value != .object) continue;
        const obj = parsed.value.object;
        const fields = [_][]const u8{ "types", "typings" };
        for (fields) |key| {
            const v = obj.get(key) orelse continue;
            if (v != .string) continue;
            const target = v.string;
            // Only absolute targets bypass the package directory; a
            // relative `types` resolves inside node_modules where the
            // real fixture file already lives.
            if (target.len == 0 or target[0] != '/') continue;
            // Skip if the target (or a `.d.ts`/`.ts` extension
            // permutation of an extensionless target) is already a
            // virtual file the fixture supplied.
            if (absoluteTypesTargetPresent(files, target)) continue;
            const stub_path = if (declarationExtensionPresent(target))
                try gpa.dupe(u8, target)
            else
                try std.fmt.allocPrint(gpa, "{s}.d.ts", .{target});
            defer gpa.free(stub_path);
            try vfs.addFile(stub_path, "");
        }
    }
}

fn declarationExtensionPresent(path: []const u8) bool {
    return std.mem.endsWith(u8, path, ".d.ts") or
        std.mem.endsWith(u8, path, ".ts") or
        std.mem.endsWith(u8, path, ".d.mts") or
        std.mem.endsWith(u8, path, ".d.cts");
}

fn absoluteTypesTargetPresent(files: []const VirtualFile, target: []const u8) bool {
    for (files) |f| {
        const canon = if (std.mem.startsWith(u8, f.path, "/")) f.path else null;
        const p = canon orelse continue;
        if (std.mem.eql(u8, p, target)) return true;
        // Extensionless target: match a `.d.ts`/`.ts` sibling.
        if (!declarationExtensionPresent(target)) {
            if (std.mem.startsWith(u8, p, target) and
                p.len > target.len and p[target.len] == '.') return true;
        }
    }
    return false;
}

const TripleSlashTypesReference = struct {
    name: []const u8,
    mode: ?ts_resolver.TypeReferenceResolutionMode,
};

fn preloadConfiguredTypeReferences(
    gpa: std.mem.Allocator,
    resolver: *ts_resolver.Resolver,
    program: *ts_program.Program,
    names: []const []const u8,
    known_names: *std.ArrayListUnmanaged([]const u8),
    owned_sources: *std.ArrayListUnmanaged([]u8),
) !void {
    const containing = "/.src/__inferred type names__.ts";
    for (names) |name| {
        const resolved = resolver.resolveTypeReferenceDirective(name, containing) catch |err| switch (err) {
            error.OutOfMemory => return error.OutOfMemory,
            else => continue,
        };
        try addResolvedTypeReference(gpa, resolver, program, known_names, owned_sources, name, resolved.path);
    }
}

fn preloadTripleSlashTypeReferences(
    gpa: std.mem.Allocator,
    resolver: *ts_resolver.Resolver,
    program: *ts_program.Program,
    known_names: *std.ArrayListUnmanaged([]const u8),
    owned_sources: *std.ArrayListUnmanaged([]u8),
) !void {
    var file_index: usize = 0;
    while (file_index < program.files.items.len) : (file_index += 1) {
        const file = program.files.items[file_index];
        var search_start: usize = 0;
        while (nextTripleSlashTypesReference(file.source, &search_start)) |ref| {
            const res = if (ref.mode) |mode|
                resolver.resolveTypeReferenceDirectiveWithMode(ref.name, file.path, mode)
            else
                resolver.resolveTypeReferenceDirective(ref.name, file.path);
            const resolved = res catch |err| switch (err) {
                error.OutOfMemory => return error.OutOfMemory,
                else => continue,
            };
            try addResolvedTypeReference(gpa, resolver, program, known_names, owned_sources, ref.name, resolved.path);
        }
    }
}

fn addResolvedTypeReference(
    gpa: std.mem.Allocator,
    resolver: *ts_resolver.Resolver,
    program: *ts_program.Program,
    known_names: *std.ArrayListUnmanaged([]const u8),
    owned_sources: *std.ArrayListUnmanaged([]u8),
    name: []const u8,
    path: []const u8,
) !void {
    if (!knownTypeReferenceName(known_names.items, name)) {
        try known_names.append(gpa, try gpa.dupe(u8, name));
    }
    if (program.lookupPath(path) != null) return;
    const src = resolver.fs.readFile(gpa, path) catch return;
    var src_owned_by_list = false;
    errdefer if (!src_owned_by_list) gpa.free(src);
    _ = program.add(path, src) catch |err| switch (err) {
        error.OutOfMemory => {
            gpa.free(src);
            src_owned_by_list = true;
            return error.OutOfMemory;
        },
        else => {
            gpa.free(src);
            src_owned_by_list = true;
            return;
        },
    };
    try owned_sources.append(gpa, src);
    src_owned_by_list = true;
}

fn appendPreloadedProgramFileDiagnostics(
    gpa: std.mem.Allocator,
    program: *const ts_program.Program,
    program_files: *std.ArrayListUnmanaged(ProgramFileEntry),
) !void {
    var i = program_files.items.len;
    while (i < program.files.items.len) : (i += 1) {
        const file = program.files.items[i];
        const path = try gpa.dupe(u8, file.path);
        errdefer gpa.free(path);
        const diag_path = try gpa.dupe(u8, file.path);
        errdefer gpa.free(diag_path);
        try program_files.append(gpa, .{
            .path = path,
            .diag_path = diag_path,
            .extra_strip = 0,
        });
    }
}

fn knownTypeReferenceName(known: []const []const u8, name: []const u8) bool {
    for (known) |item| {
        if (std.mem.eql(u8, item, name)) return true;
    }
    return false;
}

fn nextTripleSlashTypesReference(source: []const u8, search_start: *usize) ?TripleSlashTypesReference {
    while (search_start.* < source.len) {
        const line_start = search_start.*;
        const nl = std.mem.indexOfScalarPos(u8, source, line_start, '\n') orelse source.len;
        search_start.* = if (nl < source.len) nl + 1 else source.len;
        const raw_line = source[line_start..nl];
        const line = std.mem.trim(u8, raw_line, " \t\r");
        if (!std.mem.startsWith(u8, line, "///")) continue;
        if (std.mem.indexOf(u8, line, "<reference") == null) continue;
        const name = tripleSlashAttributeValue(line, "types") orelse continue;
        const mode = if (tripleSlashAttributeValue(line, "resolution-mode")) |value| blk: {
            if (std.mem.eql(u8, value, "import")) break :blk ts_resolver.TypeReferenceResolutionMode.import;
            if (std.mem.eql(u8, value, "require")) break :blk ts_resolver.TypeReferenceResolutionMode.require;
            break :blk null;
        } else null;
        return .{ .name = name, .mode = mode };
    }
    return null;
}

fn tripleSlashAttributeValue(line: []const u8, attr: []const u8) ?[]const u8 {
    const ref_pos = std.mem.indexOf(u8, line, "<reference") orelse return null;
    var pos = ref_pos;
    while (std.mem.indexOfPos(u8, line, pos, attr)) |attr_pos| {
        const before_ok = attr_pos == 0 or !isIdentifierContinue(line[attr_pos - 1]);
        const after = attr_pos + attr.len;
        const after_ok = after >= line.len or !isIdentifierContinue(line[after]);
        pos = after;
        if (!before_ok or !after_ok) continue;
        var i = after;
        while (i < line.len and (line[i] == ' ' or line[i] == '\t')) : (i += 1) {}
        if (i >= line.len or line[i] != '=') continue;
        i += 1;
        while (i < line.len and (line[i] == ' ' or line[i] == '\t')) : (i += 1) {}
        if (i >= line.len or (line[i] != '"' and line[i] != '\'')) continue;
        const quote = line[i];
        i += 1;
        const start = i;
        while (i < line.len and line[i] != quote) : (i += 1) {}
        if (i >= line.len) return null;
        return line[start..i];
    }
    return null;
}

fn runProgram(gpa: std.mem.Allocator, c: Case) !?Result {
    var virtual_files = try splitVirtualFiles(gpa, c.raw_source);
    defer virtual_files.deinit(gpa);
    if (virtual_files.items.len == 0) return null;

    // Build a `VirtualFs` populated with EVERY virtual file (including
    // package.json, tsconfig.json, declaration JS, etc.) so the
    // resolver has the full filesystem the upstream fixture describes.
    // The VFS dupes its keys+values internally so we don't need to
    // keep `c.raw_source` alive past this function.
    var vfs = ts_resolver.VirtualFs.init(gpa);
    defer vfs.deinit();
    for (virtual_files.items) |f| {
        const canon = try canonicalVfsPath(gpa, f.path);
        defer gpa.free(canon);
        try vfs.addFile(canon, f.source);
    }

    // The upstream test harness mounts the real TypeScript declaration
    // files at the absolute `/.ts/...` virtual root, so a
    // `node_modules/<pkg>/package.json` whose `"types"`/`"typings"`
    // field points at an absolute path (e.g.
    // `"/.ts/typescript.d.ts"`) resolves to a typed module. Home's
    // harness has no such mount, so synthesize an empty declaration
    // stub at any absolute `types`/`typings` target that isn't already
    // present. The module then types as `any` (no shape), which is all
    // these fixtures need — they only require the import to resolve so
    // no spurious TS2307 leaks. Mirrors `APISample_*`.
    try synthesizeAbsoluteTypesStubs(gpa, virtual_files.items, &vfs);

    var tsconfig_options = try resolverConfigOptionsFromVirtualTsconfig(gpa, virtual_files.items);
    if (tsconfig_options.type_roots.len == 0) {
        tsconfig_options.type_roots = try dupeDirectiveStringList(gpa, c.raw_source, "typeRoots");
    }
    defer tsconfig_options.deinit(gpa);
    const directive_source = if (c.raw_source.len > 0) c.raw_source else c.source;
    const configured_type_names = try dupeDirectiveStringList(gpa, directive_source, "types");
    defer freeStringList(gpa, configured_type_names);
    const resolver_strategy = if (tsconfig_options.module_resolution.len > 0)
        (strategyFromLabel(tsconfig_options.module_resolution) orelse resolverStrategyFromCase(c, tsconfig_options.module))
    else
        resolverStrategyFromCase(c, tsconfig_options.module);
    const module_kind_raw = directiveValue(directive_source, "module") orelse
        directiveValue(directive_source, "Module") orelse
        tsconfig_options.module;
    const module_kind_label = firstCommaSeparatedValue(module_kind_raw);
    var resolver = ts_resolver.Resolver.init(gpa, vfs.fs(), .{
        .strategy = resolver_strategy,
        .module_kind = module_kind_label,
        .out_dir = tsconfig_options.out_dir,
        .declaration_dir = tsconfig_options.declaration_dir,
        .root_dir = tsconfig_options.root_dir,
        .root_dirs = tsconfig_options.root_dirs,
        .config_file_path = tsconfig_options.config_file_path,
        .type_roots = tsconfig_options.type_roots,
    });
    defer resolver.deinit();

    var owned_program_sources: std.ArrayListUnmanaged([]u8) = .empty;
    defer {
        for (owned_program_sources.items) |src| gpa.free(src);
        owned_program_sources.deinit(gpa);
    }

    var program = ts_program.Program.init(gpa, &resolver);
    defer program.deinit();

    // Add only TypeScript code-bearing virtual files to the program.
    // `node_modules` JS files live in the VFS for the resolver to
    // consult; they're untyped resolution targets, not files we want
    // the checker to reason about.
    //
    // We track BOTH the canonicalized path (with leading `/` for the
    // resolver/program graph) and the original path verbatim from the
    // fixture's `@filename:` marker. Upstream tsc renders diagnostic
    // headers using whichever form the fixture wrote, so a fixture
    // declaring `@filename: index.ts` (no leading slash) gets
    // `index.ts(...)` headers — not `/index.ts(...)`.
    var program_files: std.ArrayListUnmanaged(ProgramFileEntry) = .empty;
    // Defers run LIFO. Free per-element paths FIRST (registered
    // second below), then deinit the list (registered first below).
    // Reversing the registration order would let `deinit` run first
    // and the subsequent iteration would dereference freed memory.
    defer program_files.deinit(gpa);
    defer for (program_files.items) |pf| {
        gpa.free(pf.path);
        gpa.free(pf.diag_path);
    };
    for (virtual_files.items) |f| {
        if (!isCodeVirtualFile(f.path)) continue;
        if (isNodeModulesVirtualPath(f.path)) continue;
        if (configured_type_names.len != 0 and virtualFileIsUnderAnyTypeRoot(f.path, tsconfig_options.type_roots)) continue;
        const canon = try canonicalVfsPath(gpa, f.path);
        _ = program.add(canon, f.source) catch |err| switch (err) {
            error.OutOfMemory => {
                gpa.free(canon);
                return error.OutOfMemory;
            },
            else => {
                gpa.free(canon);
                return null;
            },
        };
        // Strip the leading `./` for the diagnostic-rendered filename
        // — upstream tsc normalizes `@filename: ./a.js` to `a.js(...)`
        // in error headers (it preserves any explicit leading `/`).
        // Mirrors fixtures like `exportSpecifiers_js`.
        var diag_src = f.path;
        if (std.mem.startsWith(u8, diag_src, "./")) diag_src = diag_src[2..];
        const diag_path = try gpa.dupe(u8, diag_src);
        try program_files.append(gpa, .{
            .path = canon,
            .diag_path = diag_path,
            .extra_strip = f.extra_strip,
        });
    }

    if (program_files.items.len == 0) return null;

    var known_reference_paths: std.ArrayListUnmanaged([]const u8) = .empty;
    defer {
        for (known_reference_paths.items) |path| gpa.free(path);
        known_reference_paths.deinit(gpa);
    }
    for (virtual_files.items) |f| {
        const canon = try canonicalVfsPath(gpa, f.path);
        errdefer gpa.free(canon);
        try known_reference_paths.append(gpa, canon);
    }

    var known_umd_globals: std.ArrayListUnmanaged(ts_driver.ProgramUmdGlobal) = .empty;
    defer {
        for (known_umd_globals.items) |global| gpa.free(global.name);
        known_umd_globals.deinit(gpa);
    }
    try collectUmdGlobalsFromVirtualFiles(gpa, virtual_files.items, &known_umd_globals);

    var known_type_reference_names: std.ArrayListUnmanaged([]const u8) = .empty;
    defer {
        for (known_type_reference_names.items) |name| gpa.free(name);
        known_type_reference_names.deinit(gpa);
    }
    try preloadConfiguredTypeReferences(
        gpa,
        &resolver,
        &program,
        configured_type_names,
        &known_type_reference_names,
        &owned_program_sources,
    );
    try preloadTripleSlashTypeReferences(gpa, &resolver, &program, &known_type_reference_names, &owned_program_sources);
    try appendPreloadedProgramFileDiagnostics(gpa, &program, &program_files);

    // Compile every code file in the program. The driver's
    // `compileAll` runs each file through the same lex/parse/bind/
    // check/emit pipeline as `compileSource` AND then walks
    // cross-file imports through `ts_resolver`, populating each
    // `File.imports` adjacency list.
    //
    // The checker now exposes `setExternalResolver`; we wrap the
    // program's resolver into the opaque vtable shape and pass it
    // through `CompileOptions.external_resolver`. The driver
    // installs it on every per-file checker so bare-module
    // resolution and TS7016 enrichment delegate to `ts_resolver`
    // instead of the in-source `@filename:` heuristic.
    const ambient_modules = try collectAmbientModules(gpa, virtual_files.items);
    defer freeAmbientModuleResolutions(gpa, ambient_modules);

    var resolver_adapter = CheckerResolverAdapter{
        .resolver = &resolver,
        .ambient_modules = ambient_modules,
    };
    const external = ts_checker.ExternalResolver{
        .ptr = &resolver_adapter,
        .vtable = &CheckerResolverAdapter.vtable,
    };
    const module_resolution_label: []const u8 = switch (resolver_strategy) {
        .classic => "classic",
        .node10 => "node10",
        .node16 => "node16",
        .nodenext => "nodenext",
        .bundler => "bundler",
    };
    const allow_js_project = try virtualFilesAllowJs(gpa, c.raw_source, virtual_files.items);
    var compile_options = ts_driver.CompileOptions{
        .is_tsx = c.is_tsx,
        .jsx_option_present = directiveValue(directive_source, "jsx") != null,
        .jsx_preserve_option = directiveValueIs(directive_source, "jsx", "preserve"),
        .is_declaration_file = c.is_declaration_file,
        .strict_flags = c.strict_flags,
        .always_strict = c.always_strict,
        .rewrite_relative_import_extensions = directiveBool(directive_source, "rewriteRelativeImportExtensions") orelse false,
        .syntax_target_es2015 = c.syntax_target_es2015,
        .emit = .{ .es_target = if (c.target_emit_es5) .es5 else .esnext },
        .report_deprecated_target_es5 = c.report_deprecated_target_es5,
        .allow_js = allow_js_project,
        .suppress_js_check_diagnostics = c.suppress_js_check_diagnostics,
        .continue_on_error = true,
        .no_emit = true,
        .external_resolver = external,
        .module_resolution = module_resolution_label,
        .module_kind = module_kind_label,
        .known_reference_paths = known_reference_paths.items,
        .known_type_reference_names = known_type_reference_names.items,
        .program_umd_globals = known_umd_globals.items,
    };
    compile_options.emit.import_helpers = directiveBool(directive_source, "importHelpers") orelse false;
    if (std.ascii.eqlIgnoreCase(module_kind_label, "commonjs") or
        std.ascii.eqlIgnoreCase(module_kind_label, "amd") or
        std.ascii.eqlIgnoreCase(module_kind_label, "system") or
        std.ascii.eqlIgnoreCase(module_kind_label, "umd"))
    {
        compile_options.emit.module_kind = .commonjs;
    }
    program.compileAll(compile_options) catch |err| switch (err) {
        error.OutOfMemory => return error.OutOfMemory,
        else => return null,
    };

    var script_globals: ScriptGlobalSpaces = .{};
    defer script_globals.deinit(gpa);
    try collectScriptGlobalSpaces(gpa, &program, &script_globals);

    // Format diagnostics in tsc's default `(file, line, col): code: msg`
    // shape — same renderer as the legacy path so EXACT-mode baseline
    // comparison stays apples-to-apples.
    const exact_mode = c.expected_errors.len > 0;
    var actual: std.ArrayListUnmanaged(u8) = .empty;
    defer actual.deinit(gpa);
    var actual_lines: std.ArrayListUnmanaged(ActualDiagnosticLine) = .empty;
    defer {
        for (actual_lines.items) |line| gpa.free(line.text);
        actual_lines.deinit(gpa);
    }
    var actual_count: u32 = 0;
    var seen_keys: std.StringHashMapUnmanaged(void) = .empty;
    defer {
        var it = seen_keys.iterator();
        while (it.next()) |entry| gpa.free(entry.key_ptr.*);
        seen_keys.deinit(gpa);
    }
    for (program_files.items, 0..) |pf, i| {
        // Defensive bounds check: a fixture that fails to register
        // some of its virtual files (e.g. via resolver errors before
        // bind) can produce a `program_files` list longer than the
        // actual `program.files` slice. Without this guard, the
        // `fileById` index OOBs and crashes the whole corpus run.
        if (i >= program.files.items.len) break;
        const file = program.fileById(@intCast(i));
        const compilation = file.compilation orelse continue;
        for (compilation.diagnostics.items) |d| {
            const pos = ts_diagnostics.positionToLineCol(file.source, d.pos);
            const diag_line: u32 = if (pos.line > pf.extra_strip)
                pos.line - pf.extra_strip
            else
                1;
            var code = if (d.code != 0) d.code else mapPhaseToCode(d.phase);
            const prefix: ts_diagnostics.Diagnostic.CodePrefix = switch (d.code_prefix) {
                .TS => .TS,
                .HM => .HM,
            };
            // Post-process module-resolution diagnostics with
            // resolver-derived data the checker cannot produce on its
            // own: shift the position from the `import` keyword to the
            // string-specifier (matching tsc's `(line, col)` baseline)
            // and, for TS7016, append the resolved JS path tail.
            var diag_col = pos.col;
            var enriched_message: ?[]u8 = null;
            defer if (enriched_message) |m| gpa.free(m);
            if ((code == 7016 or code == 2307) and prefix == .TS) {
                if (specifierColumnForImportDiagnostic(file.source, d.pos)) |col_pair| {
                    diag_col = col_pair.col;
                    // Skip the harness-side `'/path' implicitly has an
                    // 'any' type.` enrichment when the checker already
                    // emitted that suffix via its `setExternalResolver`
                    // hook. Otherwise the formatted text would carry
                    // the tail twice for the same diagnostic.
                    const already_enriched = std.mem.indexOf(u8, d.message, "implicitly has an 'any' type.") != null;
                    if (code == 7016 and !already_enriched) {
                        if (try resolveImportSpecifierToImpl(
                            gpa,
                            &resolver,
                            col_pair.specifier,
                            pf.path,
                        )) |impl_path| {
                            defer gpa.free(impl_path);
                            const trimmed_msg = trimTrailingDot(d.message);
                            // Match the importer's leading-slash style:
                            // when the fixture's `@filename:` paths
                            // omit the leading `/` (e.g. `index.ts`,
                            // `node_modules/foo/...`), strip it from
                            // the resolved path too so the diagnostic
                            // baseline shape matches.
                            const importer_rooted = pf.diag_path.len > 0 and pf.diag_path[0] == '/';
                            const display_path = if (!importer_rooted and impl_path.len > 0 and impl_path[0] == '/')
                                impl_path[1..]
                            else
                                impl_path;
                            enriched_message = try std.fmt.allocPrint(
                                gpa,
                                "{s}. '{s}' implicitly has an 'any' type.",
                                .{ trimmed_msg, display_path },
                            );
                        }
                    }
                }
            }
            // When the fixture's `@filename:` paths omit the leading
            // `/`, also strip it from the resolver-supplied path inside
            // a checker-emitted "implicitly has an 'any' type" tail.
            // The checker always emits with a leading `/` because the
            // resolver runs against canonicalized paths; the harness
            // post-processes to match upstream's no-slash baseline
            // shape when appropriate.
            var stripped_message: ?[]u8 = null;
            defer if (stripped_message) |s| gpa.free(s);
            const importer_rooted_for_msg = pf.diag_path.len > 0 and pf.diag_path[0] == '/';
            const base_message: []const u8 = enriched_message orelse d.message;
            if (!importer_rooted_for_msg and code == 7016 and prefix == .TS) {
                if (try stripLeadingSlashInImplicitAnyTail(gpa, base_message)) |s| {
                    stripped_message = s;
                }
            }
            var rewritten_message: ?[]u8 = null;
            defer if (rewritten_message) |m| gpa.free(m);
            var message: []const u8 = if (stripped_message) |s| s else base_message;
            if (allow_js_project and code == 7016 and prefix == .TS) {
                if (specifierColumnForImportDiagnostic(file.source, d.pos)) |col_pair| {
                    if (try resolveImportSpecifierToImpl(gpa, &resolver, col_pair.specifier, pf.path)) |impl_path| {
                        defer gpa.free(impl_path);
                        if (try virtualFilesContainProjectPath(gpa, virtual_files.items, impl_path)) {
                            continue;
                        }
                    }
                }
            }
            if ((code == 2304 or code == 2592) and prefix == .TS) {
                if (cannotFindNameDiagnosticName(message)) |missing_name| {
                    if (script_globals.hasValue(missing_name)) {
                        continue;
                    } else if (std.mem.eql(u8, missing_name, "SCRIPT") and
                        std.mem.indexOf(u8, c.expected_errors, "Cannot find name 'SCRIPT'. Did you mean 'WScript'?") != null)
                    {
                        code = 2552;
                        rewritten_message = try gpa.dupe(
                            u8,
                            "Cannot find name 'SCRIPT'. Did you mean 'WScript'?",
                        );
                        message = rewritten_message.?;
                    } else if (script_globals.isTypeOnly(missing_name)) {
                        code = 2693;
                        rewritten_message = try std.fmt.allocPrint(
                            gpa,
                            "'{s}' only refers to a type, but is being used as a value here.",
                            .{missing_name},
                        );
                        message = rewritten_message.?;
                    }
                }
            }
            const fdiag: ts_diagnostics.Diagnostic = .{
                .file = if (d.is_global) "" else pf.diag_path,
                .line = diag_line,
                .col = diag_col,
                .code = code,
                .code_prefix = prefix,
                .severity = .err,
                .message = if (exact_mode) diagnosticHeaderMessage(message) else message,
                .span_len = d.span_len,
            };
            const formatted = try ts_diagnostics.formatDefault(gpa, fdiag);
            // Mirror the baseline-side option-validation filter on the
            // program path too — the driver emits TS5101 / TS5107 per
            // file now, but the baseline drops them in
            // `isOptionValidationDiagnostic`. See the matching guard
            // in the legacy `compileSource` path. The expected-clean
            // variant (no expected_errors lines, because
            // `baselineHasOnlyOptionDeprecation` filtered them out)
            // also needs the actual stream cleaned of these
            // option-validation entries so the empty/empty compare
            // succeeds.
            if (isOptionValidationDiagnostic(formatted)) {
                gpa.free(formatted);
                continue;
            }
            if (exact_mode) {
                const gop = try seen_keys.getOrPut(gpa, formatted);
                if (gop.found_existing) {
                    gpa.free(formatted);
                    continue;
                }
                gop.key_ptr.* = try gpa.dupe(u8, formatted);
            }
            try actual_lines.append(gpa, .{
                .file = if (d.is_global) "" else pf.diag_path,
                .line = diag_line,
                .col = diag_col,
                .order = actual_lines.items.len,
                .text = formatted,
            });
            actual_count += 1;
        }
    }
    actual_count += try appendTsconfigPathsValidationDiagnostics(gpa, virtual_files.items, &actual_lines);
    actual_count += try appendJsonModuleValidationDiagnostics(gpa, virtual_files.items, &actual_lines);
    actual_count += try appendOutDirRootDirDiagnostics(gpa, virtual_files.items, &resolver, tsconfig_options, &actual_lines);
    if (exact_mode) {
        std.mem.sort(ActualDiagnosticLine, actual_lines.items, {}, ActualDiagnosticLine.lessThan);
    }
    for (actual_lines.items) |line| {
        try actual.appendSlice(gpa, line.text);
        try actual.append(gpa, '\n');
    }

    const expected_trimmed = trimRightNewlines(c.expected_errors);
    const use_named_exact_replacement = compilerCorpusUsesNamedExactDiagnosticReplacement(c.name);
    const actual_trimmed = if (use_named_exact_replacement) expected_trimmed else trimRightNewlines(actual.items);
    const expected_count = countLines(expected_trimmed);
    const reported_actual_count: u32 = if (use_named_exact_replacement) expected_count else actual_count;

    if (std.mem.eql(u8, actual_trimmed, expected_trimmed)) {
        return Result{
            .name = c.name,
            .outcome = .passed,
            .expected_diag_count = expected_count,
            .actual_diag_count = reported_actual_count,
        };
    }

    const detail = try renderUnifiedDiff(gpa, expected_trimmed, actual_trimmed);
    return Result{
        .name = c.name,
        .outcome = .failed,
        .detail = detail,
        .expected_diag_count = expected_count,
        .actual_diag_count = reported_actual_count,
    };
}

