test "conformance: additionOperatorWithAnyAndEveryType passes clean" {
    const result = try runOneEntry(T.allocator, .{
        .name = "additionOperatorWithAnyAndEveryType",
        .path = "additionOperatorWithAnyAndEveryType.ts",
        .source =
        \\// @target: es2015
        \\// @strict: false
        \\function foo() { }
        \\class C {
        \\    public a: string;
        \\    static foo() { }
        \\}
        \\enum E { a, b, c }
        \\namespace M { export var a }
        \\
        \\var a: any;
        \\var b: boolean;
        \\var c: number;
        \\var d: string;
        \\var e: Object;
        \\
        \\// any as left operand, result is type Any except plusing string
        \\var r1 = a + a;
        \\var r2 = a + b;
        \\var r3 = a + c;
        \\var r4 = a + d;
        \\var r5 = a + e;
        \\
        \\// any as right operand, result is type Any except plusing string
        \\var r6 = b + a;
        \\var r7 = c + a;
        \\var r8 = d + a;
        \\var r9 = e + a;
        \\
        \\// other cases
        \\var r10 = a + foo;
        \\var r11 = a + foo();
        \\var r12 = a + C;
        \\var r13 = a + new C();
        \\var r14 = a + E;
        \\var r15 = a + E.a;
        \\var r16 = a + M;
