        \\// @target: es2015
        \\// @strict: false
        \\class C {
        \\    private x: string;
        \\    private get y() { return null; }
        \\    private set y(x) { }
        \\    private foo() { }
        \\
        \\    private static a: string;
        \\    private static get b() { return null; }
